var parsePersonioXml = (xml) => {
  const $ = load(xml, { xmlMode: true });
  const jobs = [];
  $("position").each((_index, element) => {
    const node = $(element);
    const text = (selector) => {
      const value = node.find(selector).first().text().trim();
      return value || null;
    };
    jobs.push({
      city: text("office"),
      country: null,
      createdAt: text("createdAt"),
      department: text("department"),
      description: node.find("jobDescriptions").text().trim() || null,
      id: text("id"),
      name: text("name"),
      office: text("office"),
      recruitingCategory: text("recruitingCategory"),
      schedule: text("schedule"),
      subcompany: text("subcompany")
    });
  });
  return jobs;
};
var buildPersonioLocation = (job) => {
  const parts = [job.office, job.city, job.country].map((value) => toNullableString(value)).filter((value) => Boolean(value));
  return parts.join(", ") || "Unknown";
};
